class Playground {
    async run(inputs) {
        const startNodeId = inputs[0].trim();
        const edgeStrings = inputs[1].split(',').map(s => s.trim());

        // 1. Parse Graph
        const nodesSet = new Set();
        const edges = [];
        edgeStrings.forEach(str => {
            const parts = str.split(':');
            const uv = parts[0].split('-');
            const u = uv[0];
            const v = uv[1];
            const weight = parts[1] ? parseInt(parts[1]) : 1;

            if (u && v) {
                nodesSet.add(u);
                nodesSet.add(v);
                edges.push({ u, v, directed: false, weight });
            }
        });

        const nodes = Array.from(nodesSet).map(id => ({ id, val: id }));

        // 2. Initialize slots
        this.graph_ds.init(nodes, edges);
        this.pq_ds.init([], 'min');
        this.visited_ds.init([]);
        this.dist_ds.init([]);

        if (!nodesSet.has(startNodeId)) {
            this.log(`Error: Start node ${startNodeId} not found in graph.`);
            return "Node not found";
        }

        this.log(`Starting Dijkstra's Algorithm from node: ${startNodeId}`);

        // 3. Initialize distances
        const distances = {};
        nodes.forEach(n => {
            distances[n.id] = Infinity;
            this.dist_ds.put(n.id, "∞");
        });

        distances[startNodeId] = 0;
        this.dist_ds.put(startNodeId, 0);

        // PQ stores strings format: "dist-node" so lexical sort acts like a basic heap for single digits, but we just use val for visual.
        // We will maintain a real JS array heap internally for exactness
        const pq = [{ dist: 0, node: startNodeId }];
        this.pq_ds.push(`0-${startNodeId}`);

        this.graph_ds.highlightNode(startNodeId, "#3b82f6"); // Initial blue
        await this.await();

        while (pq.length > 0) {
            // JS doesn't have a native heap, so we sort to simulate extract-min
            pq.sort((a, b) => a.dist - b.dist);
            const current = pq.shift();
            const u = current.node;
            const d = current.dist;

            this.pq_ds.pop();

            // Skip if we've already found a better path
            if (this.visited_ds.has(u)) continue;

            this.log(`Extracted min: ${u} with distance ${d}. Marking as settled.`);
            this.graph_ds.highlightNode(u, "#eab308"); // Processing yellow
            this.visited_ds.add(u);
            await this.await();

            const neighbors = this.graph_ds.getNeighbors(u);
            for (const neighborObj of neighbors) {
                const v = neighborObj.node;
                const weight = neighborObj.weight;

                if (this.visited_ds.has(v)) continue;

                this.graph_ds.highlightEdge(u, v, "#eab308"); // Highlight edge under consideration
                this.log(`Evaluating edge ${u}-${v} (weight: ${weight}). Current best dist to ${v} is ${distances[v] === Infinity ? '∞' : distances[v]}.`);
                await this.await();

                const newDist = d + weight;
                if (newDist < distances[v]) {
                    this.log(`Relaxation successful: ${newDist} < ${distances[v] === Infinity ? '∞' : distances[v]}. Updating path to ${v}.`);
                    distances[v] = newDist;
                    this.dist_ds.put(v, newDist);

                    pq.push({ dist: newDist, node: v });
                    this.pq_ds.push(`${newDist}-${v}`);
                    this.graph_ds.highlightNode(v, "#3b82f6"); // Blue to indicate updated
                } else {
                     this.log(`Path through ${u} is not shorter (${newDist} >= ${distances[v]}). Skipping.`);
                }

                // Reset edge highlight
                this.graph_ds.highlightEdge(u, v, "#64748b");
                await this.await();
            }

            this.graph_ds.highlightNode(u, "#10b981"); // Completed green
            this.log(`Finished processing neighbors of ${u}`);
            await this.await();
        }

        this.log("Dijkstra's Algorithm completed. Shortest paths found.");
        return distances;
    }
}
